var gap = parseInt(arguments[0]) || 20;

var allControls = Matrix.getAllObjects();
var groups = [];
for (var i = 0; i < allControls.length; i++) {
	var ctl = allControls[i];
	if (!ctl.Custom) continue;
	var match = ctl.Custom.match(/^(\d+):(\d+)$/);
	if (!match) continue;
	groups.push({
		control: ctl,
		row: parseInt(match[1]),
		ratio: parseInt(match[2]),
		origLeft: ctl.Left
	});
}

groups.sort(function(a, b) {
	if (a.row !== b.row) return a.row - b.row;
	return a.origLeft - b.origLeft;
});

var rows = {};
for (var i = 0; i < groups.length; i++) {
	var g = groups[i];
	if (!rows[g.row]) rows[g.row] = [];
	rows[g.row].push(g);
}

function applyLayout(viewerWidth) {
	for (var rowKey in rows) {
		var items = rows[rowKey];
		if (items.length === 0) continue;
		var startLeft = items[0].origLeft;
		var totalGap = gap * (items.length - 1);
		var availableWidth = viewerWidth - startLeft - gap - totalGap;
		var totalRatio = 0;
		for (var i = 0; i < items.length; i++) {
			totalRatio += items[i].ratio;
		}
		var unitWidth = availableWidth / totalRatio;
		var currentLeft = startLeft;
		for (var i = 0; i < items.length; i++) {
			var item = items[i];
			var w = unitWidth * item.ratio;
			item.control.Width = Math.floor(w);
			item.control.Left = Math.floor(currentLeft);
			currentLeft += w + gap;
		}
	}
}

Matrix.OnViewerSizeChanged = function(s, e) {
	applyLayout(e.Width);
};
